+		Pane:           "test__cod_1",
+		PID:            12346,
+		Classification: ClassWaiting,
+		Since:          now,
+		LastCheck:      now,
+	}
+	m.mu.Unlock()
+
+	states := m.GetAllStates()
+	if len(states) != 2 {
+		t.Errorf("expected 2 states, got %d", len(states))
+	}
+
+	if states["test__cc_1"] == nil {
+		t.Error("expected test__cc_1 state")
+	}
+	if states["test__cod_1"] == nil {
