+	}
+
+	// Verify states are copies
+	states["test__cc_1"].PID = 99999
+	originalStates := m.GetAllStates()
+	if originalStates["test__cc_1"].PID == 99999 {
+		t.Error("GetAllStates should return copies, not originals")
+	}
